export const ICON_NAMES = Object.freeze(Object.keys(ICON_REGISTRY))

export function normalizeIconName(name) {
  return String(name || '').trim().replace(/\.svg$/i, '')
}

export function hasIcon(name) {
  return Object.prototype.hasOwnProperty.call(ICON_REGISTRY, normalizeIconName(name))
}
